prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT (COUNT(DISTINCT ?msg) AS ?messageCount)
       (COUNT(DISTINCT ?mf)  AS ?messageFlowCount)
       (SAMPLE(?msgName)    AS ?exampleMessageName)
WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "2b18c5f00a5a46159c6cb6a3e2bc79e9" .

  ?msg a bboExt:Message ;
       tai:belongsTo ?choreo .
  OPTIONAL { ?msg bbo:name ?msgName . }

  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo .
  }
}
GROUP BY ?messageCount ?messageFlowCount ?exampleMessageName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName
       (COUNT(DISTINCT ?msg) AS ?messageCount)
       (COUNT(DISTINCT ?mf)  AS ?messageFlowCount)
       (SAMPLE(?msgName)    AS ?exampleMessageName)
WHERE {
  VALUES ?id { "2b18c5f00a5a46159c6cb6a3e2bc79e9" }

  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  { ?model tai:normalizedId ?id . }
  UNION
  { ?model tai:originalId   ?id . }

  ?msg a bboExt:Message ;
       tai:belongsTo ?choreo .
  OPTIONAL { ?msg bbo:name ?msgName . }

  OPTIONAL {
    ?mf a bboExt:MessageFlow ;
        tai:belongsTo ?choreo .
  }
}
GROUP BY ?model ?modelName
LIMIT 25
